import React, { useState } from 'react';
import './App.css';

function AudioUpload() {
    const [selectedFile, setSelectedFile] = useState(null);
    const [processedFiles, setProcessedFiles] = useState([]);
    const [errorMessage, setErrorMessage] = useState('');

    const uploadFile = async (endpoint, data) => {
        const formData = new FormData();
        formData.append('audio', selectedFile);
        Object.keys(data).forEach((key) => formData.append(key, data[key]));

        try {
            const response = await fetch(`http://localhost:5001/${endpoint}`, {
                method: 'POST',
                body: formData,
            });
            const result = await response.json();
            if (response.ok) {
                setProcessedFiles((prev) => [...prev, { name: endpoint, path: result.path }]);
            } else {
                throw new Error(result.error || 'Processing failed');
            }
        } catch (error) {
            setErrorMessage(error.message);
        }
    };

    return (
        <div className="audio-upload">
            <input type="file" accept="audio/*" onChange={(e) => setSelectedFile(e.target.files[0])} />
            <button onClick={() => uploadFile('upload', {})}>Upload</button>
            <button onClick={() => uploadFile('trim', { startTime: '0', endTime: '10' })}>Trim</button>
            <button onClick={() => uploadFile('fade', { fadeIn: '3', fadeOut: '5' })}>Fade</button>
            <button onClick={() => uploadFile('speed', { factor: '1.5' })}>Speed</button>
            <button onClick={() => uploadFile('pitch', { pitch: '1.2' })}>Pitch</button>
            <button onClick={() => uploadFile('background', {})}>Background</button>
            <button onClick={() => uploadFile('waveform', {})}>Waveform</button>
            {errorMessage && <div className="error">{errorMessage}</div>}
            <ul>
                {processedFiles.map((file, index) => (
                    <li key={index}>
                        <strong>{file.name}:</strong>{' '}
                        <a href={`http://localhost:5001/${file.path}`} target="_blank" rel="noopener noreferrer">
                            {file.path}
                        </a>
                    </li>
                ))}
            </ul>
        </div>
    );
}

export default AudioUpload;
